"use client";

import React from "react";
import { useState } from "react";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Button } from "@/components/ui/button";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from "@/components/ui/command";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
// import SelectInput from "react-select";
import { supabase } from "@/lib/supabaseClient";
// import MultiSelectDropdown from "../../../components/MultiSelectDropdown";

const { data, error } = await supabase.from("tag").select("name");

const CreateRecipe = () => {
  //   const [selectedTags, setSelectedTags] = useState<string[]>([]);

  // Handle the selected tags
  //   const handleTagChange = (tags: string[]) => {
  //     setSelectedTags(tags);
  //   };
  const [open, setOpen] = useState(false);
  const [value, setValue] = useState("");

  if (error) {
    console.error(error);
  } else {
    console.log(data.sort()); // Will contain an array of user objects
  }

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-2xl font-bold mb-4">Create Recipe</h1>
      <form>
        <div className="mb-4">
          <Label
            htmlFor="recipe-name"
            className="block text-sm font-medium text-gray-700"
          >
            Name
          </Label>
          <Input
            type="text"
            id="recipe-name"
            placeholder="Name"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-green-500 focus:ring-green-500 sm:text-sm"
          />
          <Label htmlFor="ingredients">Ingredients</Label>
          <Button>+ Add ingredient</Button>
          <Input
            type="text"
            id="ingredient-name"
            placeholder="Ingredient name"
          />
          <Label htmlFor="instructions">Instructions</Label>
          <Label htmlFor="recipe-tag">Tag</Label>
          <Popover open={open} onOpenChange={setOpen}>
            <PopoverTrigger asChild>
              <Button variant="outline" role="combobox" aria-expanded={open}>
                {value
                  ? data?.find((tag) => tag.name === value)?.name
                  : "Select tags..."}
              </Button>
            </PopoverTrigger>
            <PopoverContent>
              <Command>
                <CommandInput placeholder="Search tags..." />
                <CommandList>
                  <CommandEmpty>No tags found.</CommandEmpty>
                  <CommandGroup>
                    {data
                      ?.sort((a, b) => a.name.localeCompare(b.name))
                      .map((tag) => (
                        <CommandItem
                          key={tag.name}
                          value={tag.name}
                          onSelect={(currentValue: string) => {
                            setValue(
                              currentValue === value ? "" : currentValue
                            );
                            setOpen(false);
                          }}
                        >
                          {tag.name}
                        </CommandItem>
                      ))}
                  </CommandGroup>
                </CommandList>
              </Command>
            </PopoverContent>
          </Popover>

          <Select>
            <SelectTrigger>
              <SelectValue placeholder="Select tag(s)" />
            </SelectTrigger>
            <SelectContent>
              {data
                ?.sort((a, b) => a.name.localeCompare(b.name))
                .map((tag) => (
                  <SelectItem key={tag.name} value={tag.name}>
                    {tag.name}
                  </SelectItem>
                ))}
            </SelectContent>
          </Select>
          {/* <Input type="" id="tags" placeholder="Tags" /> */}
          {/* <MultiSelectDropdown
            initialTags={selectedTags} // Pass selected tags when editing
            onTagChange={handleTagChange} // Callback to update selected tags
          /> */}
        </div>
        <Button
          type="submit"
          className="bg-green-600 text-white px-4 py-2 rounded hover:bg-green-700"
        >
          Submit
        </Button>
      </form>
    </div>
  );
};

export default CreateRecipe;
